// LoadSeason loads the seasonTeamStanding's Season into the .R struct
func (o *SeasonTeamStanding) LoadSeason(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.Season = nil

	related, err := o.Season(mods...).One(ctx, exec)
	if err != nil {
		return err
	}

	related.R.SeasonTeamStandings = SeasonTeamStandingSlice{o}

	o.R.Season = related
	return nil
}

// LoadSeason loads the seasonTeamStanding's Season into the .R struct
func (os SeasonTeamStandingSlice) LoadSeason(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	seasons, err := os.Season(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range seasons {

			if !(o.SeasonID == rel.ID) {
				continue
			}

			rel.R.SeasonTeamStandings = append(rel.R.SeasonTeamStandings, o)

			o.R.Season = rel
			break
		}
	}

	return nil
}

